class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) : characters(characters), combinationLength(combinationLength) {
        indices.resize(combinationLength, 0);
        hasNextResult = hasNext();
    }

    string next() {
        string result;
        for (int i = 0; i < combinationLength; i++) {
            result += characters[indices[i]];
        }
        nextIndices();
        hasNextResult = hasNext();
        return result;
    }

    bool hasNext() {
        return hasNextResult;
    }

private:
    string characters;
    int combinationLength;
    vector<int> indices;
    bool hasNextResult;

    void nextIndices() {
        for (int i = combinationLength - 1; i >= 0; i--) {
            if (indices[i] < characters.size() - combinationLength + i) {
                indices[i]++;
                for (int j = i + 1; j < combinationLength; j++) {
                    indices[j] = indices[i] + j - i;
                }
                return;
            }
        }
    }

    bool hasNext() {
        for (int i = combinationLength - 1; i >= 0; i--) {
            if (indices[i] < characters.size() - combinationLength + i) {
                return true;
            }
        }
        return false;
    }
};
```
efficiency: HIGH
time complexity: O(1) for next() and hasNext(), O(n) for constructor
space complexity: O(n)
energy implications: LOW
